INSERT INTO response_answers (response_id, section, question_key, value_text) VALUES (currval('responses_id_seq'), 'freitext', 'gelungen', 'Wir hatten dieses Mal wenige methodische Umsetzungen, die über eine "Diskussion" hinausgingen und gelungen waren. Trotzdem war es hilfreich, wenn Punkte möglichst konkret vorgedacht waren, es Struktur gab und die zu entscheidenen Punkte hervorgehoben waren.');
INSERT INTO response_answers (response_id, section, question_key, value_text) VALUES (currval('responses_id_seq'), 'freitext', 'themen', 'leider fast alle?!');
INSERT INTO response_answers (response_id, section, question_key, value_text) VALUES (currval('responses_id_seq'), 'freitext', 'sonstiges', 'Die Methode zur Jahresplanung fand ich nicht zielführend. Warum haben wir uns noch einmal alle Inhalte des letzten Jahres angeschaut?! Und die langen Diskusisonen ob Punkte im kommenden Jahr stratgisch oder operativ sein werden hat uns viel Zeit gekostet, ohne dass mir der konkrete Mehrwert klar ist.');
